import React from 'react';
import { createRouter, createRootRoute, createRoute } from '@tanstack/react-router';
import { Root } from './routes/root.tsx';
import Index from './routes/index.tsx';
import WorkflowAiRoute from './routes/workflow-ai.tsx';

// Create the root route
const rootRoute = createRootRoute({
  component: Root,
});

// Create the index route
const indexRoute = createRoute({
  getParentRoute: () => rootRoute,
  path: '/',
  component: Index,
});

// Create the workflow-ai route
const workflowAiRoute = createRoute({
  getParentRoute: () => rootRoute,
  path: '/workflow-ai',
  component: WorkflowAiRoute,
});

// Create the route tree
const routeTree = rootRoute.addChildren([indexRoute, workflowAiRoute]);

// Create the router with proper base configuration for GitHub Pages
const router = createRouter({ 
  routeTree,
  basepath: '/',
  // For GitHub Pages, we might need to handle hash routing
  history: typeof window !== 'undefined' ? window.history : undefined,
});

// Register things for typesafety
declare module '@tanstack/react-router' {
  interface Register {
    router: typeof router;
  }
}

export default router;